// Auto-generated chapters data from PDF questions
export const chaptersData = {
  "chapter1-concepts": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是操作系统？为什么学习操作系统？它的重要性在什么地方？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">操作系统是最基本的系统软件，是一组有效管理和控制计算机系统的硬件和\n软件资源，合理地对各类作业进行调度以组织和控制系统工作流程，并方便用户\n使用计算机的程序的集合。操作系统被称为计算机之魂，它连接硬件与软件、用\n户与机器，决定了计算机的性能、稳定性和安全性。学习操作系统不仅能帮助人\n们理解计算机的底层运行机制，更能提升编程能力、系统设计思维和问题解决能\n力，是计算机科学与技术领域不可或缺的核心知识。无论是开发应用程序、设计\n系统架构，还是研究前沿技术，操作系统的原理和思想都将成为你进阶的 “内\n功心法”。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">从资源管理的角度，操作系统主要研究哪些问题？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">从资源管理的角度，操作系统的主要功能就是对处理器、存储器、I/O 设\n备以及文件（数据和程序）这四类资源进行有效的管理。处理器管理负责处\n理器的分配与控制；存储器管理负责内存的分配与回收；I/O 设备管理负责 I/O\n设备的分配、回收与操纵；文件管理负责文件的存取、共享和保护。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">操作系统追求的目标是什么？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">操作系统追求的目标包括方便性、有效性、可扩展性、开放性。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">操作系统的主要功能有哪些？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">操作系统的主要功能包括处理器管理功能、存储器管理功能、设备管理\n功能、文件管理功能、接口管理功能。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">处理器管理有哪些功能？它们的主要任务是什么？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">进程管理功能主要包括进程控制、进程同步、进程通信、进程调度等。\n进程控制功能完成进程创建、撤销进程、唤醒进程、阻塞进程等操作；进程\n同步功能完成多个进程（含线程）运行的互斥与协调；进程通信功能用来实\n现进程之间的信息交换；进程调度功能是从进程的就绪队列中选出一个进程\n把处理器分配给它，并为它设置运行现场使其投入运行。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">存储器管理有哪些功能？它们的主要任务是什么？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">存储器管理的主要功能包括内存分配和回收、内存保护、地址映射和内\n存扩充等。内存分配的主要任务是：为每道程序分配内存空间，使它们“各\n得其所”；提高存储器的利用率，尽量减少不可用的内存空间（碎片）；允\n许正在运行的程序申请附加的内存空间，以适应程序和数据动态增长的需要。\n内存保护的主要任务是：确保每道用户程序都仅在自己的内存空间内运行，\n彼此互不干扰；不允许用户程序访问操作系统的程序和数据，也不允许用户\n程序转移到非共享的其他用户程序中去执行。地址映射的任务是在 CPU 执行\n程序过程中把程序的逻辑地址转换为物理地址。内存扩充的任务是借助于虚\n拟存储技术，从逻辑上扩充内存容量，使系统能够提供比物理内存大的容量。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">设备管理有哪些功能？它们的主要任务是什么？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">设备管理的功能主要包括设备分配、缓冲管理和设备处理。设备分配的\n基本任务是根据用户进程的 I/O 请求、系统当前的资源情况，按照某种设备\n分配算法为用户进程分配所需的设备；设备使用完后，系统应立即回收，以\n分给其他进程使用，提高设备的利用率。缓冲管理的主要任务是缓和 CPU 与\nI/O 设备间速度不匹配的矛盾，提高 CPU 与 I/O 设备之间以及各设备之间的\n并行性。设备处理的基本任务是实现 CPU 与设备控制器之间的通信，即接收\n由 CPU 发来的 I/O 命令，如读/写命令，转换为具体要求后，传给设备控制器，\n启动设备去执行；同时也将由设备控制器发来的信号传送给 CPU，如设备是\n否完好、是否准备就绪、I/O 操作是否已完成等，并据此进行相应的处理，在\n设备完成具体的 I/O 操作后及时响应中断，进行相应的中断处理。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">文件管理有哪些功能？它们的主要任务是什么？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">文件管理的功能包括文件存储空间的管理，目录的结构和管理，文件的\n读、写管理和存取控制。文件存储空间的管理负责为每个文件分配必要的外\n存空间，提高外存利用率，并有助于提高文件系统的速度。目录管理为每个\n文件建立目录项，并对众多目录项进行有效组织。文件的读、写管理根据用\n户的请求，从外存中读取数据或将数据写入外存；文件的存取控制防止未经\n核准的用户存取文件，防止冒名顶替存取文件，防止以不正确的方式使用文\n件。</div>\n  </div>\n</div>\n",
  "chapter1-evolution": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">操作系统的发展经历了哪几个主要阶段？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">操作系统的发展经历了单道批处理系统、多道批处理系统、分时系统、\n实时系统、通用操作系统、网络操作系统、分布式操作系统等阶段。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">批处理有几种类型，都促进了计算机系统哪些方面的发展？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">批处理主要有单道批处理系统和多道批处理系统两种。单道批处理系统\n主要是为了解决人机矛盾以及 CPU 与 I/O 设备速度不匹配的矛盾，它的出现\n推动了计算机系统在资源利用、自动化管理、软硬件协同等多个关键领域的\n突破，为后续操作系统的发展奠定了基础。多道批处理系统采用了多道程序\n设计技术，它允许多个程序同时进入内存，交替在 CPU 中运行。多道批处理\n系统不仅提高了 CPU 的利用率，同时也改善 I/O 设备和内存的利用率，从而\n提高了整个系统的资源利用率和系统吞吐量，最终提高了整个系统的效率。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">何谓联机 I/O？何谓脱机 I/O？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">联机 I/O 指 I/O 设备直接与主机连接，数据的输入输出过程由主机（通\n过操作系统或监控程序）实时控制和管理的模式。在这种模式下，I/O 设备\n与主机共享系统资源，操作过程与主机的运行紧密耦合。脱机 I/O 指 I/O 设\n备不直接由主机控制，而是通过独立的外围处理机（或专用设备）完成数据\n的输入输出，再将处理后的结果“批量”传递给主机的模式。在这种模式下，\nI/O 操作与主机的运行过程分离，二者通过中间存储介质（如磁带、磁盘）\n间接交互。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">为什么引入多道程序（设计）？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">操作系统中引入多道程序设计的核心目的是解决单道程序设计中“资源\n利用率极低”的根本问题，通过让多个程序“并发”运行，最大化 CPU、内\n存、外设等硬件资源的使用效率，从而提升整个计算机系统的吞吐量和处理\n能力。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">是什么原因推动了分时系统的发展，其主要特点是什么？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">为了满足人们对于人机交互工作方式的需求，分时系统应运而生。分时\n系统的主要特点包括同时性、独立性、交互性、共享性、及时性。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">实时系统的特点是什么，它与分时系统的相似和不同之处在哪里？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">实时系统的特点包括实时性、操作的可预计性、人机对话的简单性、高\n安全与高可靠性。实时系统与分时系统的相似之处在于二者都支持多任务并\n发与资源共享，主要差别在于交互能力和响应时间。分时系统的交互能力较\n强，而实时系统大都是具有特殊用途的专用系统，其交互能力受到一定的限\n制。分时系统的响应时间一般都是以人能接受的时间延迟来确定的，其响应\n时间一般在秒数量级；而实时系统的响应时间则要求视应用场合而定，主要\n以控制对象或信息处理过程所能接受的时间延迟来确定，可能是秒级，也可\n能是毫秒级，甚至是微秒级。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">实时系统的主要应用对象是什么？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">实时系统的核心特征是能在严格的时间约束内响应外部事件并完成处理，\n其应用对象主要集中在对“时间确定性”“可靠性” 要求极高的场景，例如：\n工业控制与智能制造、交通运输与智能出行、军事与国防领域、医疗设备与\n生命支持、嵌入式与物联网场景、金融交易与实时数据处理等。</div>\n  </div>\n</div>\n",
  "chapter1-structure": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是微内核操作系统？它具有哪些优点？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">微内核操作系统是一种以“精简内核”为核心理念，将传统操作系统的\n大部分功能移至用户态实现的架构设计。其核心思想是：仅保留操作系统最\n基础、最关键的功能在内核态（微内核），而将文件系统、设备驱动、进程\n间通信等非核心功能作为独立的“用户态服务进程”运行，通过内核提供的\n标准化接口实现服务间的交互。微内核操作系统的优点包括可靠性、扩充性、\n移植性、适宜于分布式处理的计算环境等。</div>\n  </div>\n</div>\n",
  "chapter2-process-states": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">简述程序顺序执行时的特征。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">程序顺序执行时具有如下特征：\n（1）顺序性。处理器的操作严格按照程序所规定的顺序执行，只有当上一个操\n作完成后，下一个操作才能开始执行。除了人为的干预造成机器暂时停顿外，前\n一个动作的结束就意味着后一个动作的开始。\n（2）封闭性。程序一旦开始运行，其执行结果不受外界因素影响。因为程序在\n运行时独占系统的全部资源，除初始状态外，这些资源的状态只能由本程序改变，\n不受任何外界因素的影响。\n（3）可再现性。只要程序执行时的初始条件和执行环境相同，当程序重复执行\n时，都将获得相同的结果（即程序的执行结果与时间无关）。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">简述程序并发执行时的特征。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">程序并发执行时具有如下特征：\n（1）间断性。程序在并发执行时，由于它们共享资源或为完成同一项任务而相\n互合作，致使并发程序之间形成了相互制约关系。这种相互制约关系将导致并发\n程序具有“执行—暂停执行—执行”这种间断性的活动规律。\n（2）失去封闭性。程序在并发执行时，多个程序共享系统中的各种资源，因而\n这些资源的状态将由多个程序来改变，致使程序的运行失去封闭性。这样，一个\n程序在执行时必然会受到其他程序的影响。\n（3）不可再现性。程序并发执行时，由于失去了封闭性，也将导致失去其运行\n结果的可再现性。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是进程？操作系统中为什么要引入进程？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">进程是程序在一个数据集合上的执行过程，是系统进行资源分配和调度的一\n个独立单位。在多道程序环境下，程序的并发执行破坏了程序的封闭性和可再现\n性，使得程序和计算结果不再一一对应，程序活动不再处于一个封闭系统中，程\n序的运行出现了许多新的特征。在这种情况下，程序这个静态概念已经不能如实\n地反映程序活动的这些特征，为此，人们引入了一个新的概念——进程。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">进程的基本状态有哪些？进程的状态转换关系是什么样的？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">通常，一个进程至少应具有以下三种基本状态：就绪状态、执行状态和阻塞\n状态。进程在执行过程中并不是固定处于某一个状态，其状态会随着自身的推进\n和外界条件的变化而发生变化。下图给出了进程的三种基本状态以及引起状态转\n换的典型原因。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">为什么要引入进程的挂起状态？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">在某些操作系统中，为了更好地管理和调度进程及适应系统的功能目标，引\n入了挂起状态。引入挂起状态可能基于下述原因：（1）系统有时可能出故障或\n某些功能受到破坏，这时就需要暂时将系统中的进程挂起，以便系统故障消除后，\n再将这些进程恢复到原来状态。（2）用户检查自己作业的中间执行情况和中间\n结果时，因同预期想法不符而产生怀疑，这时用户要求挂起他的进程，以便进行\n某些检查和改正。（3）系统中有时负荷过重（进程数过多）资源数相对不足，\n从而造成系统效率下降，此时需要挂起一部分进程以调整系统负荷，等系统中负\n荷减轻后再恢复被挂起进程的运行。（4）在操作系统中引入了虚拟存储管理技\n术后，需要区分进程是驻留在内存还是外存，此时可以用挂起表示进程驻留在外\n存。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是进程控制块？进程控制块中包含哪些进程信息？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">为了准确地描述每个进程并对进程进行有效的管理与控制，操作系统为每个\n进程定义了一个专门的数据结构——进程控制块（Process Control Block，PCB）。\n在操作系统中，PCB 唯一地标识了一个进程，是进程实体的一部分。进程控制\n块中通常包含以下信息：进程标识符、进程当前状态、进程队列指针、程序和\n数据地址、进程优先级、CPU 现场保护区、通信信息、家族关系、资源清单等。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">引起进程创建的事件有哪些？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">一般情况下，引起进程创建的事件大致有以下几类：（1）用户登录。在交\n互式操作系统中，当用户登录进入系统时，操作系统要建立新进程（如命令解释\n进程），负责接收并解释用户输入的命令。（2）调度新作业。在批处理系统中，\n提交给操作系统的作业通常存放在磁带或磁盘上。当作业调度程序选中某个作业\n时，便为该作业创建进程，分配必要的资源并插入就绪队列。（3）操作系统提\n供服务。当运行中的用户程序向操作系统提出某种请求时，操作系统也会创建进\n程来完成用户程序所需要的服务功能。（4）应用请求。前三种情况下都是由操\n作系统根据需要为用户创建进程，事实上正在运行的进程也可以根据需要来创建\n一个新进程，使之与父进程并发执行，以完成特定的任务。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">简述进程创建的过程。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">创建一个新进程的主要操作过程如下：（1）向操作系统申请一个空闲的 PCB。\n具体来说，从系统的 PCB 表中找出一个空闲的 PCB 表项，并指定唯一的进程标\n识号 PID。（2）为新进程分配资源。根据新进程提出的资源需求为其分配资源，\n例如为新进程分配内存空间以存放其程序及数据。（3）初始化新进程的 PCB。\n在新进程的 PCB 中填入进程名、家族信息、程序和数据地址、进程优先级、资\n源清单及进程状态等信息，一般新进程的状态被设置为就绪状态。（4）将新进\n程的 PCB 插入到进程就绪队列。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">引起进程终止的事件有哪些？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">引起进程终止的事件大致有以下几类：（1）进程正常结束。当一个进程完\n成其任务后，应该将其终止并释放其所占有的资源。（2）进程异常结束。在进\n程运行期间，如果出现了某种异常事件，则进程被迫结束运行。导致进程异常结\n束的事件较多，比如运行超时、内存不足、越界错误、I/O 故障、算术运算错误\n等。（3）外界干预。进程因外界的干预而被迫结束运行。外界干预包括操作人\n员或操作系统的干预，如为了解除死锁，操作人员或操作系统要求撤销进程；或\n者当父进程终止时，操作系统会级联终止其子孙进程；再或者父进程有权请求操\n作系统终止其子孙进程。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">简述进程终止的过程。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">进程终止的一般过程如下：（1）从系统的 PCB 表中找到被终止进程的 PCB。\n（2）检查被终止进程的状态是否为执行状态，若是则立即停止该进程的执行，\n设置重新调度标志，以便在该进程终止后将处理器分配给其他进程。（3）检查\n被终止进程是否有子孙进程，若有子孙进程还应终止该进程的子孙进程。（4）\n回收该进程占有的全部资源并回收其 PCB。</div>\n  </div>\n</div>\n",
  "chapter2-thread-concepts": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是线程？进程和线程有什么区别？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">在引入线程的操作系统中，线程是隶属于进程的一个实体，是比进程更小的\n一个运行单位。一个进程可以有一个或多个线程，这些线程共享该进程所拥有的\n资源，如地址空间（代码、数据及文件）、大部分管理信息（子进程、定时器、\n信号等）以及 I/O 设备等，同时每个线程也有自己的一些必不可少的资源：一个\n线程 ID、一组寄存器集合、一个用户栈与一个内核栈、线程控制块。进程和线\n程的区别主要体现在以下几个方面：（1）从调度的基本单位看，在传统的 OS\n中，进程作为独立调度和分派的基本单位，是能独立运行的基本单位，在每\n次被调度时，都需要进行上下文切换，开销较大。在引入线程的 OS 中，线\n程作为调度和分派的基本单位，是能独立运行的基本单位，当线程切换时，\n仅需保存和设置少量的寄存器内容，切换代价远低于进程。（2）从并发性的\n角度来看，在引入线程的 OS 中，不仅进程之间可以并发执行，同一个进程中的\n多个线程之间也可以并发执行，而且不同进程中的线程也能并发执行，从而使得\nOS 具有更好的并发性，从而能更加有效地提高系统资源的利用率和系统的吞吐\n量。（3）从拥有资源的角度看，进程可以拥有资源，并作为系统中资源分配的\n一个基本单位。然而，线程本身不拥有系统资源，而是仅有一点必不可少的、能\n保证独立运行的资源。（4）从独立性角度来看，在同一进程中的不同线程之间\n的独立性要比不同进程之间的独立性低得多。（5）从系统开销来看，在创建或\n撤消进程时，系统都要为之分配和回收进程控制块、分配和回收其它资源。OS\n为此所付出的开销，明显大于线程创建或撤消时所付出的开销。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">线程的实现方式有哪些？各有什么优缺点？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">线程的实现方式包括用户级线程、内核级线程和组合线程。在用户级线\n程实现中，线程管理的所有工作都由应用程序完成，操作系统内核意识不到线程\n的存在。这样的线程仅存在于用户空间中，其创建、终止、线程间的同步与通信、\n同一进程内多线程间的切换等功能，均可以在不经过系统调用、无须内核支持的\n情形下由应用程序实现。在内核级线程实现方式中，线程管理的所有工作都由操\n作系统内核完成，应用程序并没有参与其中，即无论是用户进程中的线程，还是\n系统进程中的线程，它们的创建、终止和切换等都依靠内核，在内核空间中实现。\n内核为进程及其内部的所有线程维护上下文环境。有些操作系统把用户级线程和\n内核级线程两种实现方式进行组合，提供了组合线程。在组合线程中，内核支持\n内核级线程的建立、调度和管理，同时，也允许用户应用程序建立、调度和管理\n用户级线程。一些内核支持线程对应多个用户级线程，程序员可按应用需要和机\n器配置对内核支持线程的数目进行调整，以达到较好的效果。</div>\n  </div>\n</div>\n",
  "chapter2-communication": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">进程间通信的方式有哪些？简述每种通信方式的特点。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">目前，高级进程通信方式可以分为四大类：共享存储器系统、消息传\n递系统、管道通信系统以及客户/服务器系统。（1）共享存储器系统中，进程通\n过共享内存中的某些数据结构或存储区来实现通信。为了实现通信，进程在通信\n前应向系统申请建立一个共享存储区，并指定该共享存储区的关键字；若该共享\n存储区已经建立，则将该共享存储区的描述符返回给申请者；然后，申请者把获\n得的共享存储区附接到进程的地址空间上。这样，进程便可以像读写普通存储器\n一样地读写共享存储区。（2）消息传递系统中，进程间的数据交换以消息为单\n位，程序员直接利用系统提供的一组通信命令（原语）来实现进程间通信。操作\n系统隐藏了通信的实现细节，大大简化了通信程序编制的复杂性，因而获得了广\n泛的应用。（3）管道通信系统中，管道是用于连接读进程和写进程以实现它们\n之间通信的共享文件，向管道提供输入的发送进程（即写进程）以字符流形式将\n大量的数据送入管道，而接收管道输出的接收进程（即读进程）可以从管道中接\n收数据。（4）客户/服务器系统，实现方法主要包括：套接字（Socket）、远程\n过 程调 用（Remote Procedure Call ，RPC）和远程方法调用（ Remote Method\nInvocation， RMI）。一个套接字就是一个通信标识类型的数据结构，包含了通\n信目的地址、通信使用端口号、通信网络的传输层协议、进程所在的网络地址以\n及针对客户或服务器程序提供的不同系统调用，是进程通信和网络通信的基本构\n件。远程过程调用 RPC，是一个通信协议，用于通过网络连接的系统。该协议\n允许运行于一台主机（本地）系统上的进程调用另一台主机（远程）系统上的进\n程。负责处理远程过程调用的进程有两个，一个是本地客户进程，另一个是远程\n服务进程，这两个进程通常也被称为网络守护进程，主要负责在网络间的消息传\n递，一般情况下，这两个进程都是处于阻塞状态，等待消息。远程方法调用类似\n于远程过程调用，是远程过程调用在面向对象程序设计中的实现形式。</div>\n  </div>\n</div>\n",
  "chapter3-critical-section": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">封装性与结构化：管程是一种语言级别的封装机制，将共享资源及其\n操作集中定义，并通过编译器自动实现互斥（如进入队列管理），减\n少了程序员分散管理同步操作的负担。信号量是一种低级同步原语，\n需要程序员显式地在代码中插入 wait 和 signal 操作来管理互斥与同\n步，容易因操作分散导致错误。\n2. 互斥实现方式：管程的互斥访问由编译器隐式保证（如自动添加互斥\n锁），进程无需显式申请互斥锁。信号量需程序员手动设置互斥信号\n量（如 mutex），并通过 wait 和 signal 操作显式管理互斥。\n3. 同步机制：管程使用条件变量（如 x.wait 和 x.signal）实现同步，允\n许进程在条件不满足时阻塞并释放管程控制权，避免忙等待。信号量\n通过整型或记录型信号量的数值变化直接控制同步，但可能因操作顺\n序不当导致死锁或饥饿（如生产者-消费者问题中 wait 操作的顺序需\n谨慎）。\n4. 可读性与维护性：管程将同步逻辑集中管理，提高了代码的模块化和\n可维护性。信号量的操作分散在多个进程中，需全局协调，增加了代\n码的复杂性和出错风险。\n5. 适 用 场 景 ： 管 程 适 用 于 语 言 或 系 统 级 支 持 的 同 步 （ 如 Java 的\nsynchronized 关键字），更适合复杂同步问题的结构化解决。信号量\n更灵活，可用于底层同步实现，但需要程序员承担更多管理责任。\n7. 解释条件变量在管程中的作用，并提供一个实际的情境示例。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">条件变量（Condition Variable）在管程（Monitor）中用于实现进程或线\n程间的复杂同步，它允许线程在某个条件不满足时主动阻塞并释放管程的互\n斥权，直到其他线程改变条件并通知它。条件变量的核心作用是避免忙等待\n（Busy-Waiting），提高资源利用率，同时确保同步的正确性。\n条件变量在管程中的作用：</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">解释互斥与同步的概念，以及它们在进程同步中的作用。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">互斥的概念及其在进程同步中的作用</div>\n  </div>\n</div>\n",
  "chapter3-semaphores": "<p class=\"text-slate-500 text-sm italic\">Under construction...</p>",
  "chapter3-classic-problems": "<p class=\"text-slate-500 text-sm italic\">Under construction...</p>",
  "chapter4-scheduling-levels": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">资源利用率：使系统中的处理机和其他所有资源尽可能保持忙碌状态，以\n提高资源利用率。\n2. 公平性：确保所有进程获得合理的CPU 时间，避免饥饿现象。公平性是\n相对的，相同类型进程应获得相同服务，不同类型进程可根据紧急程度或\n重要性提供不同服务。\n3. 平衡性：调度算法应尽可能保持系统资源使用的平衡性，使CPU 和各种\n外部设备经常处于忙碌状态（例如，避免计算型作业和I/O 型作业资源使\n用失衡）。\n4. 策略强制执行：必须准确执行所制定的策略（包括安全策略），即使某些\n工作可能因此延迟。\n二、批处理系统的调度目标\n1. 平均周转时间短\n2. 系统吞吐量高\n3. 处理机利用率高\n2. 在选择调度方式和调度算法时，应遵循的准则是什么?</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">选择调度方式和算法时应遵循以下准则：\n 资源利用率：使CPU 和其他资源尽可能保持忙碌。\n 公平性：确保每个进程都能获得合理的CPU 时间，避免饥饿现象。\n 平衡性：使系统中CPU 和外部设备的使用保持平衡。\n 策略强制执行：确保安全策略等必须被严格执行。\n 系统类型目标：\no 批处理系统：平均周转时间短、系统吞吐量高、CPU 利用率高。\no 分时系统：响应时间快、均衡性（响应时间与任务复杂度匹配）。\no 实时系统：保证截止时间、可预测性。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">何谓静态和动态优先级?确定静态优先级的依据是什么?</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">静态优先级：在进程创建时确定，且在整个运行期间保持不变。动态优先级：\n在进程运行过程中根据情况（如等待时间增长）动态调整。确定静态优先级的依\n据：\no 进程类型（系统进程优先级高于用户进程）。\no 资源需求（对资源需求少的进程优先级高）。\no 用户要求（紧迫程度和付费情况）。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">在时间片轮转法中，应如何确定时间片的大小?</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">时间片应略大于一次典型交互所需的时间（如几次键盘输入），以确保大多\n数交互进程能在一个时间片内完成。时间片太小会导致频繁上下文切换，增加系\n统开销；太大则退化为FCFS，影响响应时间。通常时间片取10~100ms。</div>\n  </div>\n</div>\n",
  "chapter4-scheduling-algorithms": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">在批处理系统、分时系统和实时系统中，各采用哪几种进程（作业）调度算\n法?</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\"> 批处理系统：先来先服务（FCFS）、短作业优先（SJF）、优先级调度、\n高响应比优先（HRRN）。\n 分时系统：时间片轮转（RR）、多级反馈队列调度。\n 实时系统：最早截止时间优先（EDF）、最低松弛度优先（LLF）、优先\n级调度（可抢占）。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">试比较FCFS 和SJF 两种进程调度算法。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">特性 FCFS SJF\n调 度 原\n则 按到达顺序调度 按估计运行时间最短优先调度\n优点 简单、公平 平均等待时间短、吞吐量高\n缺点 长作业可能导致短作业等待时间\n长\n需预知运行时间、长作业可能饥\n饿\n适 用 场\n景 批处理系统 批处理系统（短作业多）</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">按调度方式可将实时调度算法分为哪几种?</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\"> 非抢占式调度：\no 非抢占式轮转调度\no 非抢占式优先级调度\n 抢占式调度：\no 基于时钟中断的抢占式优先级调度\no 立即抢占的优先级调度</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是最早截止时间优先调度算法?举例说明之。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">定义：根据任务的截止时间确定优先级，截止时间越早优先级越高。\n例如，假设两个周期任务：\no 任务A：周期20ms，执行时间10ms\no 任务B：周期50ms，执行时间25ms\n调度器优先调度截止时间更早的任务（如A₁在t=0 时截止时间早于B₁），确保\n错过截止时间的风险最小。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是最低松弛度优先调度算法?举例说明之。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">定义：根据任务的紧急程度（松弛度=截止时间-剩余运行时间-当前时间）\n确定优先级，松弛度越小优先级越高。\n例子：\n任务A：截止时间20ms，剩余运行时间10ms，当前时间t=0，松弛度=10ms\n任务B：截止时间50ms，剩余运行时间25ms，松弛度=25ms\n优先调度A（松弛度更小）。若在t=10ms 时A₂松弛度变为20ms，B₁松弛度变\n为15ms，则切换调度B₁。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">通过一个例子来说明通常的优先级调度算法为什么不能适用于实时系统?</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">举例（优先级倒置）：假设三个进程：P₁（优先级高）、P₂（中）、P₃（低）。\nP₃占用临界资源，P₁等待该资源。但P₂抢占P₃的CPU，导致P₃无法及时释放资\n源，P₁被阻塞且等待时间不可预测。\n问题：普通优先级调度无法保证高优先级任务在截止时间内完成，缺乏可预测性，\n不满足实时系统要求。\n解决方案：采用优先级继承（如P₃继承P₁的优先级）避免被P₂抢占。</div>\n  </div>\n</div>\n",
  "chapter5-deadlock-causes": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">破坏互斥条件（不现实）；\n2. 破坏请求和保持条件（如预先分配策略）；\n3. 破坏非剥夺条件（剥夺已分配资源）；\n4. 破坏循环等待条件（如有序分配策略）。\n9. 下面关于死锁问题的叙述哪些是正确的？哪些是错误的？说明原因。\n1）参与死锁的所有进程都占有资源。\n2）参与死锁的所有进程总至少有两个进程占有资源。\n3）死锁只发生在无关进程之间。\n4）死锁可发生在任意进程之间。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">参与死锁的所有进程都占有资源。\n正确。每个死锁进程至少持有一个资源。\n参与死锁的所有进程总至少有两个进程占有资源。\n正确。死锁至少涉及两个进程，每个至少持有一个资源。\n死锁只发生在无关进程之间。\n错误。死锁可发生在任意进程之间，无关或相关均可。\n死锁可发生在任意进程之间。\n正确。只要满足四个必要条件，任何进程之间都可能发生死锁。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">在一个死锁中，只包含一个进程是否可能？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">不可能。死锁至少涉及两个或更多进程相互等待对方所占有的资源。单个进\n程无法形成循环等待。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">死锁和饥饿的主要区别是什么？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">死锁：多个进程相互等待对方释放资源，都无法继续执行。\n饥饿：某个进程长期得不到所需资源，无法执行，但其他进程可能仍在执行。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">一台计算机共 8 台磁带机，由 N 个进程共享，每个进程最多要 3 台，请分析\nN 为多少时不会有死锁？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">每个进程最多需要 3 台，系统共有 8 台。要避免死锁，需满足：\nN×(3−1)+1≤8⇒2N+1≤8⇒2N≤7⇒N≤3.5N×(3−1)+1≤8⇒2N+1≤8⇒2N≤7⇒N≤3.5\n因此，当 N≤3 时，系统不会发生死锁。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">有1（2 个）、2（1 个）两类资源和两个进程1、2，两个进程均以：申请1 ⟶\n申请2 ⟶ 申请1 ⟶ 释放1 ⟶ 释放2 ⟶ 释放1的顺序使用资源，求可能达\n到的死锁点，并画出此时的资源分配图。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">死锁可能发生在：\n P1 占用 R1 并请求 R2；\n P2 占用 R2 并请求 R1。\n此时资源分配图中存在循环等待环，形成死锁。图略（可参考文中图 5-1 或 5-3\n风格绘制）。</div>\n  </div>\n</div>\n",
  "chapter5-deadlock-prevention": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">解决死锁的方法有几种？哪种方法最容易实现？哪种方法使资源的利用率最\n高？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">四种方法：预防、避免、检测、解除。\n最容易实现：预防死锁（如有序分配策略）；\n资源利用率最高：避免死锁（如银行家算法）。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">预防死锁的途径具体有哪些？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">通过破坏四个必要条件之一：</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">如果在银行家算法例题中最后一步，把0发出的请求向量改为\n0(0，1，0)，系统是否能将资源分配给它？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">需重新执行银行家算法安全性检查。\n若分配后系统仍处于安全状态，则可分配；否则不可。\n根据文中例题数据，需具体计算（略）。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">在银行家算法中，若出现表 5-8 所示的资源分配情况，请问：\n表 5-8 习题 11 资源分配情况\nProcess Allocation Need Available\n1 0 0 3 2 0 0 1 2 1 6 2 2\n2 1 0 0 0 1 9 5 0\n3 1 3 5 4 2 3 5 6\n4 0 3 3 2 0 6 5 2\n5 0 0 1 4 0 6 5 6\n1）该状态是否安全？\n2）若进程2提出请求(1，2，2，2)后，系统能否将资源分配给它？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">略，需具体计算安全性序列和请求响应。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">有 5 个进程1、2、3、4、5共用三类资源 A（17 个）、B（5 个）、C\n（20 个），0时刻系统状态如表 5-9 所示。\n表 5-9 习题 12 资源分配情况\n进 程 最 大 需 求 已 分 配\n1 5 5 9 2 1 2\n2 5 3 6 4 0 2\n3 4 0 11 4 0 5\n4 4 2 5 2 0 4\n5 4 2 4 3 1 4\n请问：\n1）0时刻是否为安全状态？若安全请给出安全系列。\n2）0时刻，2: (0，3，4)，能否分配？为什么？\n3）在 2）的基础上4:  2，0，1 ，能否分配？为什么？\n4）在 3）的基础上1:  0，2，0 ，能否分配？为什么？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">略，需使用银行家算法逐步分析。</div>\n  </div>\n</div>\n",
  "chapter5-deadlock-recovery": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">试简化图 5-6 中的资源分配图，并利用死锁定理给出结论。\n图 5-6 资源分配图</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">需逐步简化资源分配图：找出既不阻塞又非孤立的进程，释放其资源；若最\n终所有进程成为孤立结点，则无死锁；否则存在死锁。\n结论需根据简化结果判断：简化后的资源分配图如下，由于仍然存在非孤立节点，\n故系统中存在死锁。</div>\n  </div>\n</div>\n",
  "chapter6-memory-allocation": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是程序的链接？并说明其作用。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">程序的链接是由链接程序将编译后形成的一组目标模块及它们所需的库函数\n链接在一起。其作用是形成一个完整的装入模块。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">为什么需要重定位功能？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">在多道程序设计系统中，可用的内存空间被多个进程共享。通常情况下，程\n序员事先并不知道程序执行期间驻留在内存中的其他程序，同时还希望提供一个\n巨大的就绪进程池，以便把活动进程换入或换出内存，提高处理器的利用率。程\n序换出到磁盘后，下次再换入时很难放到与换出前相同的内存区域中，因此需要\n把进程重定位到内存的不同区域。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">逻辑地址、相对地址、物理地址、绝对地址之间的关系？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">逻辑地址是指与当前数据在内存中的物理分配地址无关的访问地址，逻辑地\n址和相对地址都是CPU 生成的地址，相对地址是逻辑地址的一个特例。物理地\n址和绝对地址都是指数据在内存中的实际分配地址。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是动态重定位？并说明其作用。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">动态重定位是指作业装入内存后的所有地址仍使用相对地址，在指令真正要\n执行时才将相对地址转换为绝对地址。其作用是程序换出到磁盘后，下次再换入\n时可以把进程重定位到内存的不同区域。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">固定分区方式中，使用大小相等的分区和大小不等的分区各有什么优势与不\n足？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">大小相等的分区具有方便管理的优势；不足之处在于灵活性较差，超出固定\n分区大小的分区无法执行，且内存利用率非常低。大小不等的分区灵活性较好，\n同时产生较少的内部碎片，减少浪费；不足之处在于管理相对复杂。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">固定分区存在什么问题？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">分区数量在系统生成阶段已经确定，会限制了系统中活动进程的数量。由于\n分区的大小是在系统生成阶段事先设置的，因而小作业不能有效地利用分区空间，\n必然造成浪费。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">试比较内部碎片和外部碎片。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">外部碎片产生于动态分区，内部碎片产生于单一连续分区和固定分区。均是\n对内存的浪费。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是紧凑，在内存分配中起到什么作用？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">将内存中的所有作业进行移动，使它们全部相连，使得原来分散的小分区被\n拼接成一个大分区而用来加载用户作业，这个过程就是“紧凑”。在内存分配中\n起到的作用是可以获得大的空闲空间。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">试述伙伴系统的基本思想。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">伙伴系统是综合固定分区和动态分区方案的一种较为合理的折中方案。所有\n分区大小均为2k 个字，L&lt;=K&lt;=U，其中2L 表示分配的最小块的尺寸，2U 表示分\n配的最大块的尺寸；通常2U 是可供分配的整个内存的大小。最初，可用于分配\n的整个空间被视为一个大小为2U 的块。当需要为进程分配一个长度为s 的空间\n时，首先计算i 值，使2i-1&lt;s&lt;=2i，然后在空闲分区中查找大小为2i 的空闲分区。\n若找到，则把该空闲分区分配给进程。否则，在分区大小为2i+1 的空闲分区中查\n找，若找到则把该空闲分区分为相等的两个分区，称为“一对伙伴”，其中一个分\n区用于分配，另一个则成为大小为2i 的空闲分区。若不存在，则继续查找，如此\n循环直到找到为止。回收分区时，若被回收分区的伙伴也为空闲分区，则将一对\n伙伴进行合并，如此循环，直到无法合并为止。</div>\n  </div>\n</div>\n",
  "chapter6-paging-segmentation": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">页式地址的结构及其地址变换过程。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">页式地址包括页号和在该页中的偏移量，前n 位为页号P，用户程序最多有\n2n 页；后m 位为偏移量W，即页面大小为2mB。分页地址变换机构会自动将逻\n辑地址分为页号和页内地址两部分，由硬件机构执行以页号为索引的页表检索。\n在执行检索之前，先将页号与页表长度进行比较，如果页号大于或等于页表长度，\n则表示本次访问的地址已超越进程的地址空间，系统将产生地址越界中断。否则，\n将逻辑地址转换为物理地址。转换过程为：1）提取页号，即逻辑地址最左侧的\nn 位；2）以此页号为索引，查找该进程页表中相应的页框号k；3）页框的起始\n物理地址为k×2m，加上偏移量即为被访问字节的物理地址，将偏移量附加到页\n框号后面即可构建物理地址。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是快表，其作用是什么？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">快表即具有并行查询能力的高速缓冲寄存器，又称“联想寄存器”。作用是\n用来存放最近用过的页表项，减少存取数据时内存访问次数，提高内存访问速度。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">段式地址结构及其地址变换过程。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">段式地址由段号和偏移量两部分组成，偏移量m 位，段号n 位，则一\n个作业最多有2n 段，每段最大长度为2mB。地址转换过程：提取段号，并与段\n表长度进行比较，若段号&gt;段表长度，则段号太大，访问越界，产生越界中断信\n号；否则以这个段号为索引，查找该进程段表中该段的起始物理地址；提取偏移\n量，将其与段长进行比较，若偏移量&gt;段长，则同样产生越界中断信号，地址无\n效；若为有效地址，则将该段的起始物理地址与偏移量相加，得到要访问的物理\n地址。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">试比较分页与分段。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">分页和分段相同点在于二者均属于内存离散分配管理方式，且都通过地址映\n射机构实现地址变换。不同点主要体现在：页是信息的物理单位，段是信息的逻\n辑单位；页的大小固定且由系统决定，段的长度不固定，取决于用户所编写的程\n序，由编译程序在对源程序进行编译时根据信息的性质来划分；分页系统中程序\n地址空间是一维的，分段系统中程序地址空间是二维的。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">试述段页式存储管理的基本思想。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">段页式存储管理方式是分段和分页原理的结合，先将用户程序分成若干段，\n再把每段分成若干页，并为每一个段赋予一个段名。为段页式存储管理的地址结\n构，由段号、段内页号及页内地址这3 部分组成。</div>\n  </div>\n</div>\n",
  "chapter7-demand-paging": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">简述常规存储器管理方式的两个主要特征及其对系统性能的影响。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">常规存储器管理方式具有一次性和驻留性两个特征，使得程序在运行中不用\n或暂时不用的程序或数据占用了大量的内存空间，而其他需要运行的作业又无法\n装入内存运行。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">简述局部性原理对于虚拟存储的作用。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">基于局部性原理，可以将程序的一部分装入内存，其余部分留在外存，就可\n以开始运行程序。程序运行过程中，当所需要的信息不在内存时，由操作系统将\n所需要的内容调入内存，继续运行。同时，操作系统将内存中暂时不适用的内容\n换出到外存上，以腾出空间存放需要调入内存的内容。这样，系统好像为用户提\n供了一个比实际内存容量大得多的存储空间，这就是虚拟存储。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">请求分页与简单分页存储方式有什么区别？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">简单分页系统的页表是一维的，请求分页系统的页表需要增加一些控制信息\n字段；请求分页系统需要具备缺页请求和页面置换功能，简单分页系统不需要；\n简单分页需要程序全部进入内存才可执行，请求分页系统程序只需要一部分进入\n内存即可执行。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是虚拟存储器及其实现的两个主要条件。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">程序运行过程中，当所需要的信息不在内存时，由操作系统将所需要的内容\n调入内存，继续运行。同时，操作系统将内存中暂时不适用的内容换出到外存上，\n以腾出空间存放需要调入内存的内容。这样，系统好像为用户提供了一个比实际\n内存容量大得多的存储空间，这就是虚拟存储。实现虚拟存储的两个主要条件是\n缺页请求和页面置换功能。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">说明请求分页系统中页面访问过程。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">首先检索快表也就是图中的 TLB，尝试找到所要访问的页。若找到，则修\n改其访问位，说明该页面被访问，如果执行写操作则同时要修改修改位，供页面\n置换时选择页面参考。若在快表中没有找到该页对应的页表项，则要到内存中去\n查找页表，通过状态位来了解该页是否已调入内存。如果已调入内存，则到内存\n中取出，同时将该页的页表项写入快表。当快表已满时，则应先调出按某种算法\n所确定的页的页表项，然后再将该页的页表项写入。若该页未调入内存，则产生\n缺页中断，由操作系统将该页从外存调入内存。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">说明什么是快表及其作用。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">为了提高地址变换速度，可在地址变换机构中增设一个具有并行查询能力的\n高速缓冲寄存器，称为“联想寄存器”（associative memory）或“快表”。作用\n是用以存放最近用过的页表项，减少内存读写过程中内存访问次数，提高速度。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">说明什么是固定分配和可变分配。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">固定分配策略为一个进程在内存中分配固定数量的页框，以供执行时使用。\n可变分配策略允许分配给一个进程的页框在该进程的生命周期中不断地发生变\n化。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">说明什么是局部置换和全局置换。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">局部置换是从内存中移出的一页必须由同一个进程的另一页置换。全局置换\n是把内存中所有未被锁定的页都作为置换的候选页，而不管它们属于哪个进程。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">简要说明两种页面读取策略。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">常用的两种方法是请求调页和预调页两种策略。请求调页，只有当访问到某\n页中内容时才将该页取入内存。由请求调页策略所确定调入的页是一定会被访问\n的，但每次仅调入一页，故须花费较大的系统开销，增加了磁盘 I/O 的启动频率。\n预调页是一次调入若干个连续的页，这样会比隔一段时间调入一页更高效些。但\n因为调入的页并不是缺页中断请求的页，如果调入的一批页面中的大多数都未被\n访问，则又是低效的。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">试述“抖动”的定义及其产生原因。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">在虚拟页式存储管理中，有可能出现这样的现象：对于刚刚被淘汰出去的页，\n进程可能马上又要访问它。故又需将它调入内存，因无空闲内存页面而又要淘汰\n另一页，而后者很可能是即将被访问的页。于是造成系统需要花费大量的时间忙\n于进行这种频繁的页面调换从而无法完成用户所要求的工作，这称为抖动现象。</div>\n  </div>\n</div>\n",
  "chapter7-page-replacement": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">试比较 LRU 和 OPT 置换算法。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">最佳（Optimal，OPT）置换算法是一种理想化的算法，它具有最好的性能，\n但因为它以未来页面使用情况为参照，要求操作系统必须知道将来的事情，因此\n实际上是无法实现的，通常被用来作为标准来评价其他置换算法的优劣。最近最\n久未用（Least Recently Used, LRU）置换算法是根据页面调入内存后的使用情况\n做出决策的。由于无法预知各页面将来的使用情况，基于程序局部性原理，可以\n利用“最近的过去”作为“最近的将来”的预测依据，因此，LRU 置换算法是\n选择最近最久未使用的页面予以淘汰。</div>\n  </div>\n</div>\n",
  "chapter8-io-control": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">I/O 设备分类依据及方式。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">按信息组织、传送单位分类：块设备，字符设备；按使用特性分类：存储设\n备，输入输出设备；按设备共享属性分类：独占设备，共享设备，虚拟设备；按\n数据传输速率分类：低速设备，中速设备，高速设备。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是独占设备、共享设备和虚拟设备？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">独占设备是一旦分配给某个进程使用，在释放前其他进程不得使用；共享设\n备是允许多个进程同时使用的设备；通过一定的辅助存储器和控制程序，可将一\n台独享设备虚拟为共享设备，这个具有了新特性的设备就称为虚拟设备。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">设备与设备控制器之间有哪些信号线？并简要说明各自的作用。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">数据信号线，用于在设备和设备控制器之间传送数据信号；控制信号线，作\n为由设备控制器向I/O 设备发送控制信号时的通路；状态信号线，用于传送指示\n设备当前状态的信号。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">设备控制器的基本组成及其具备的功能。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">设备控制器主要包含控制寄存器、状态寄存器、数据寄存器、地址译码器等。\n其中，控制寄存器用来接收和识别CPU 发来的命令；数据寄存器用来实现控制\n器与CPU 之间、控制器和外设之间的数据交换；状态寄存器则是为了记下设备\n的状态（例如设备就绪、设备忙、操作错误等），供CPU 了解；地址译码器是\n为了识别每个设备的地址。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是I/O 通道？设置它的作用是什么？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">I/O 通道是一种特殊的处理机，它具有执行I/O 指令的能力，并通过执行通\n道程序来控制I/O 操作。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">I/O 通道与一般处理器的比较。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">I/O 通道与一般的处理机不同，主要表现在：其指令类型单一，这是由于通\n道硬件比较简单，其所能执行的命令主要局限于I/O 操作有关的指令；通道没有\n自己的内存，通道所执行的通道程序是放在主机的内存中的，换言之，是通道与\nCPU 共享内存。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">I/O 控制方式有哪些？并依据CPU 介入程度对它们进行比较。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">程序直接控制进行的I/O，基本特征就是需要CPU 不断地执行测试设备的状\n态信息，只有到设备就绪位表示为“就绪”时，CPU 才可以执行一条传送数据\n的指令；中断驱动进行的I/O，每当完成一个字（节）的I/O 时，控制器便要向\nCPU 请求一次中断；直接存储器存取进行的I/O，数据在内存和设备之间直接传\n送，不需要CPU 干预，仅在一个数据块传输完成后，DMA 才向CPU 发出一个\n中断请求；大型计算机系统的通道式进行的I/O，进一步减少CPU 的干预，对一\n组数据块的读（或写）及有关的控制和管理需要CPU 的一次干预。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">试述程序直接控制I/O 方式的处理流程。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">CPU 向设备输出数据的大致过程为：在处理机向控制器发出一条I/O 指令，\n启动输入设备输入数据时，要同时把状态寄存器中的忙/闲标志busy 置为1，然\n后便不断地循环测试busy（称为轮询）。当busy=l 时，表示输入机尚未输完一\n个字（符），处理机应继续对该标志进行测试，直至busy=0，表明输入机已将\n输入数据送入控制器的数据寄存器中。于是处理机将数据寄存器中的数据取出，\n送入内存指定单元中，这样便完成了一个字（符）的I/O。接着再去启动读下一\n个数据，并置busy=l。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">试述中断I/O 控制方式的处理流程。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">CPU 执行设备驱动程序，向设备控制器发出启动设备的指令，使外设处于\n准备工作状态，然后CPU 继续执行其他工作（或因为当前进程由于I/O 而被阻\n塞后，通过进程调度选择其他进程投入运行）；设备控制器按照I/O 指令的要求，\n启动并控制I/O 设备的工作，此时CPU 与外设是并行操作的；在输入就绪、输\n出完成或发生某种错误的情况下，设备控制器便向CPU 发出一个中断信号；CPU\n接收到中断信号后，保护现场，然后将控制转给相应中断处理程序；中断处理程\n序分析中断原因，执行相应的处理工作，完成后退出中断，恢复现场，将控制转\n回被打断的执行位置；CPU 恢复对被打断的任务的处理。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">说明中断I/O 控制方式与DMA 方式有何不同。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">中断I/O 控制方式是以字（节）为单位进行I/O 的，每当完成一个字（节）\n的I/O 时，控制器便要向CPU 请求一次中断；DMA 方式数据在内存和设备之间\n直接传送，不需要CPU 干预，仅在一个数据块传输完成后，DMA 才向CPU 发\n出一个中断请求。</div>\n  </div>\n</div>\n",
  "chapter8-buffering": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">试述引入缓冲的目的并比较几种缓冲技术。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">引入缓冲的目的是为了改善CPU 与I/O 设备间速度不匹配的矛盾；减少对\nCPU 的中断频率，放宽对中断响应时间的限制；提高 CPU 和 I/O 设备之间的并\n行性。分位单缓冲，双缓冲，多缓冲，缓冲池几种技术。单缓冲是操作系统提供\n的最简单的缓冲类型，当用户进程发出I/O 请求时，操作系统给该操作分配一个\n缓冲区；双缓冲给操作分配两个系统缓冲区，在一个进程往一个缓冲区中传送数\n据的同时，操作系统可以清空另一个缓冲区；多缓冲通常组织成循环缓冲的形式，\n来平滑计算与输入输出设备、输入设备与输出设备并行双方之间的数据流；缓冲\n池是在池中设置多个可供若干个进程共享的缓冲区当进程需要执行I/O 操作时，\n向系统申请一个缓冲，系统就在公共缓冲池中进行分配，形成按需分配的管理方\n式。</div>\n  </div>\n</div>\n",
  "chapter8-disk-scheduling": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">磁盘I/O 速度与哪些因素有关？如何提高磁盘I/O 速度？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">寻道时间，旋转延迟时间，数据传输时间。为了减少对文件的访问时间，应\n采用一种最佳的磁盘调度算法，以使各进程对磁盘的平均访问时间最小。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">试分别FCFS、SSFS、SCAN 几种磁盘调度算法的优缺点。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">FCFS 磁盘调度算法简单且公平，但未考虑优化寻道，当有大量的进程访问\n者竞争一个磁盘时其性能就会变得很差；SSFS 磁盘调度算法选择使磁头臂从当\n前所在位置开始移动最少的磁盘I/O 请求，以使得每次的寻道时间均为最短，但\n是缺点在于并不能保证平均寻道时间最短，且有可能发生“饥饿”现象；SCAN\n磁盘调度避免了饥饿现象，但存在问题是当磁头正在向里，或向外运动的过程中，\n刚好有一个新的I/O 请求所涉及的磁道也刚好是刚刚读取过的磁道，按照SCAN\n算法是不会考虑这样的问题，这个I/O 请求要等到磁臂一直运动到再无该方向最\n后的请求时，才向返回的方向运动，再逐步在返回的方向选择与当前磁道距离最\n近的请求I/O 的磁道，这样就延迟了该I/O 的请求。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">试比较N-step-SCAN 和FSCAN 两种调度算法的异同。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">这两种调度算法均是对SCAN 和CSCAN 调度算法的改进，有效避免“磁臂\n黏着”问题。N-step-SCAN 策略把磁盘请求队列分成若干个长度为N 的子队列，\n按照FCFS 的策略依次处理这些子队列，每次选中的子队列按照SCAN 策略进行\n处理。在处理某个队列时，新请求必须添加到其他某个队列中。而FSCAN 是一\n种使用两个子队列的策略，实质上是N-step-SCAN 调度算法的简化。一个是由\n当前所有请求磁盘I/O 的进程形成的队列，由磁盘调度按SCAN 算法进行处理。\n另一个是在扫描期间，将新出现的所有磁盘I/O 请求放入等待处理的请求队列。\n这样，所有的新请求都将被推迟到下一次扫描时处理。</div>\n  </div>\n</div>\n",
  "chapter9-file-structure": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是数据项、记录和文件？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">域（Field）又称为数据项（Item），是基本的数据单元。一个域包含一个值，\n如学生的名字、入学日期，或者是传感器读取的数值。\n记录（Record）是一组相关域的集合，可视为应用程序的一个单元。\n文件（File）是一组相关记录的集合，它被用户和应用程序视为一个实体，\n并可通过名字访问。如学生登记表是一个文件，每条记录是一个学生的信息。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是文件管理系统？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">从用户的角度来看，文件系统是操作系统的重要组成部分。文件系统允许用\n户创建称为文件的数据集。文件拥有一些必备的属性以方便用户使用，并保证系\n统性能。\n对文件管理的要求包括可以访问文件、保存文件并维护文件内容的完整性，\n这些是操作系统的文件管理系统所提供的基本功能。文件管理系统由系统实用程\n序组成，它们可作为具有特权的应用程序来运行。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">简述堆文件、顺序文件、索引顺序文件和索引文件的组织方式。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">堆（Pile）是最简单的文件组织形式。数据按它们到达的顺序被收集，每条\n记录由多个数据域组成。堆的目的仅仅是积累大量的数据并保存数据。记录可以\n有不同的域，或者域相似但顺序不同。\n顺序文件是最常用的文件组织形式。在这类文件中，每条记录都使用一种固\n定的格式。所有记录都具有相同的长度，并由相同数量、长度固定的域按特定的\n顺序组成。由于每个域的长度和位置已知，因此只需保存各个域的值，每个域的\n域名和长度是该文件结构的属性。有一个特殊的域被称为关键域（Key Field）。\n关键域唯一地标识这条记录。\n索引顺序文件保留了顺序文件的关键特征：记录按照关键域的顺序组织。但\n它增加了两个特征：一是对记录分组，二是对每组的第一个记录建立索引。索引\n提供了快速接近目标记录的查找能力。一组中的记录可根据本组首记录的指针进\n行顺序定位。\n索引文件为每个记录创建一个索引。因此，对记录的存储位置不再有限制，\n只要有一个索引的指针指向这条记录即可。此外，索引文件还很容易支持变长记\n录。\n可以使用两种类型的索引。完全索引包含主文件中每条记录的索引项，为了\n易于查找，索引自身被组织成一个顺序文件。部分索引只包含那些有感兴趣域的\n记录的索引项。对于变长记录，某些记录并不包含所有的域。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">试比较顺序文件和索引顺序文件的查找速度。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">要查找某个特定的域，首先要查找索引，查找关键字域值等于目标关键字域\n值或者位于目标关键字域值之前且最大的索引，然后在该索引所指的主文件中记\n录的位置处开始顺序查找。为说明该方法的有效性，假设有一个包含 100 万条记\n录的顺序文件，要查找某个特定的关键字域值，平均需要访问 50 万条记录。若\n创建一个包含了 1000 项的索引，索引中的关键字域均匀分布在主文件中（每个\n索引指向一个有 1000 条记录的组），为查找特定记录，平均只需在索引文件中\n进行 500 次访问，定位到索引后接着在主文件中进行 500 次访问，从而定位到记\n录。此时，查找的开销从顺序文件的平均 500000 次降低到了 1000 次。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">试比较外存分配方式的顺序分配、链接分配和索引分配。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">连续分配（Contiguous Allocation）是指在创建文件时，给文件分配一组连续\n的块。这是一种使用大小可变分区的预分配策略。在文件分配表中，每个文件只\n需要一个表项，用于说明起始块和文件的长度（块的个数）。从单个顺序文件的\n角度来看，连续分配是最好的。对于顺序处理，可以同时读入多个块，从而提高\nI/O 性能。\n连续分配也存在一些问题。首先，会出现外部碎片，从而很难找到空间大小\n足够的连续块。因此，时常需要执行紧凑算法来拼接磁盘中的空闲块，而紧凑算\n法本身需要很大的开销如图所示。其次，因为是预分配，需要在创建文件时声明\n文件的大小，这将会导致前面已经讨论过的文件动态增长时的问题。\n链接分配（Chained Allocation）。分配基于单个块，链中的每块除存储文件\n数据以外，还包含指向下一块的指针。在文件分配表中，每个文件同样只需要一\n个表项，用于声明起始块和文件的长度。链接分配可根据需要灵活地分配块。块\n的选择非常简单：任何一个空闲块都可加入链中。由于一次只需一个块，因此不\n必担心外部碎片的出现。这种类型的物理组织方式最适合于顺序处理的顺序文件。\n索引分配（Indexed Allocation）解决了连续分配和链接分配中的许多问题。\n对于索引分配，每个文件在文件分配表中都有一个表项指向索引块。分配给该文\n件的每个盘块号都保存在索引块中。索引分配基于固定大小的块。索引分配可以\n消除外部碎片，且不需要进行文件碎片整理。索引分配支持顺序访问文件和直接\n访问文件，因而是最普遍的一种文件分配形式。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">在索引分配中为什么要引入多级索引？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">在使用一级索引时，文件大小不能超过一个索引块所容纳的盘块号个数。在\n为大文件分配磁盘空间时，如果所分配的盘块的盘块号已经装满一个索引块，操\n作系统须再为该文件分配另一个索引块，用于将以后继续为之分配的盘块号记录\n于其中，此时，应为这些索引块再建立一级索引，称为第一级索引，即系统再分\n配一个索引块，作为第一级索引的索引块，将第一块、第二块、...等索引块的盘\n块号填入到此索引表中，这样便形成了两级索引分配方式。如果文件非常大时，\n还可用三级、四级索引分配方式。</div>\n  </div>\n</div>\n",
  "chapter9-directory-management": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是文件目录？什么是两级目录和树形目录？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">文件目录是一种数据结构，用于标识系统中的文件属性及其物理地址，提供\n给各种操作。文件目录所包含的信息，特别是与存储相关的信息，都由操作系统\n管理。目录自身也是一个文件，它可被各种文件管理例程访问。\n两级目录结构将文件目录分成主文件目录和用户文件目录两级。系统为每个\n用户建立一个单独的用户文件目录 UFD（User File Directory），其中的表项登记\n了该用户建立的所有文件及其说明信息。主文件目录 MFD（Master File Directory）\n则记录系统中各个用户文件目录的情况，每个用户占一个表目，表目中包括用户\n名及相应用户目录所在的存储位置等。\n在现代操作系统中，多采用三级或三级以上的多级目录结构，即树形结构目\n录。它可以明显地提高对目录的检索速度和文件系统的性能。主目录在这里被称\n为根目录，在每个文件目录中，只能有一个根目录，每个文件和每个目录都只能\n有一个父目录。把数据文件称为树叶，其他的目录均作为树的结点，或称为子目\n录。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">绝对路径和相对路径有何不同？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">在树形目录结构中，从根目录到任何数据文件都只有一条唯一的通路。在该\n路径上，从树的根（即主目录）开始，把全部目录文件名与数据文件名依次地用\n“/”连接起来，即构成该数据文件唯一的路径名。\n把 从 当前目录开始直到数据 文件为止所构成的路径名称为相对路径名\n（Relative Path Name），而把从树根开始的路径名称为绝对路径名（Absolute Path\nName）。</div>\n  </div>\n</div>\n",
  "chapter9-disk-space-management": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">请分析位示图方式的优缺点。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">位示图是利用二进制的一位来表示磁盘中一个盘块的使用情况。通常用”0”\n表示盘块空闲，用”1”表示已分配。磁盘上的所有盘块都有一个二进制位与之\n对应，这样，由所有盘块所对应的位构成一个集合，称为位示图。\n位示图方法的主要优点是：从位示图中很容易找到一个或一组相邻接的空闲\n盘块。例如，现需要找到 6 个相邻接的空闲盘块，这只需在位示图中找出 6 个其\n值连续为“0”的位即可。此外，由于位示图很小，占用空间少，因而可将它保\n存在内存中，进而使每次进行盘区分配时，无须首先把盘区分配表读入内存，从\n而节省了许多磁盘的启动操作。\n位示图方法的缺点是在分配和回收盘块时要做复杂的转换操作，耗费时间且\n不直观；另外，随着磁盘容量增长，盘块数增多，位示图要相应增大。</div>\n  </div>\n</div>\n",
  "chapter10-security-threats": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">计算机系统面临的主要安全威胁有哪些？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">（1） 计算机病毒\n计算机病毒是由人编写的一类具有攻击性和破坏性，能自我复制的计算机程\n序。计算机病毒对系统威胁极大，有些病毒会删除系统中的文件，格式化硬盘分\n区，不停地复制和传播使得系统无法正常工作甚至陷入瘫痪。\n（2）特洛伊木马\n表面上是一段执行合法功能的计算机程序，实际上它能够在用户毫无防备的\n情况下，监视用户的键盘输入，抓取用户的屏幕显示，然后把用户的各种密码和\n敏感信息发送给攻击者。\n（3） 天窗\n指嵌入在操作系统里的一段非法代码。渗透者利用该代码提供的方法侵入操\n作系统而不受检查。\n（4） 恶意程序\n运行在计算机网络及移动互联网上带有攻击意图的程序，攻击者发布恶意程\n序的目的是窃取用户数据、恶意扣费、远程攻击、消耗流量、恶意传播等，进而\n影响计算机及移动终端设备运行，损害用户利益，危害互联网安全。\n（5） 计算机漏洞\n所谓计算机漏洞是指计算机软硬件系统中存在某些缺陷，这些缺陷能被攻击\n者利用。\n（6） DDoS 攻击\n即分布式拒绝访问攻击（Distributed Denial of Service，DDoS），攻击者利\n用 DDoS 攻击器控制大量计算机网络设备，向攻击目标发送大量数据，使被攻击\n目标因资源耗竭而瘫痪。\n（7） APT 攻击\n即高级持续性攻击（Advanced Persistent Threat，APT），攻击者针对特定目\n标（个人、组织或公司）进行长时间持续（可长至数月之久）的攻击，以窃取数\n据和进行间谍活动，常利用投递诱惑性钓鱼邮件实现其攻击。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">操作系统存在哪些安全性问题？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">（1）对用户身份的鉴别过程容易受攻击\n一些主流的操作系统通过简单的口令来确认用户身份，这种鉴别是单向的和\n不安全的。\n（2） 传统访问控制技术不能解决开域授权问题\n传统的访问控制理论表现为一种关口控制的概念，不让不符合条件者进去，\n但是一旦取得进入的资格和权利，在范围内的活动行为就无法监管了，进入后想\n做什么就做什么。\n（3）操作系统不能确认自身的完整性\n操作系统自身的身份和完整性是否可信也需要得到确认。\n（4）操作系统的安全政策不能适应环境的变化\n操作系统必须应用于真实环境才可以发挥其作用。\n（5）操作系统中的部分主体与客体之间缺少相互验证\n安全操作系统中的主体是能够发起行为的实体，如进程等，主体发出访问操\n作，是存取要求的主动方。客体是主体行为的承担者，通常意义的客体包括文件、\n目录、共享内存、消息、信号量、管道、存储器缓冲器、磁盘和外部设备等。客\n体的概念还可以推广到所有的对象概念上，客体甚至还可以是进程。进程本身也\n可以被操作，作为行为的受体。值得注意的是，大部分安全操作系统在处理客体\n时，没有区分具体的客体类型，将不同类型的客体采用同一方法标志和处理。\n（6）用软件方式实现的安全核不能满足安全操作系统发展的需要\n安全操作系统一个重要的特征是安全核。安全模型的实施及相关接口和配置\n数据均在安全核中。</div>\n  </div>\n</div>\n",
  "chapter10-protection-encryption": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">对称加密和非对称加密有何区别？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">加密（encryption）用于把系统中的数据（称为明文）转换为密文。在数据\n加密技术中，有两个关键要素：一是算法，二是密钥。私钥加密，又称对称加密，\n因为这种算法解密密钥和加密密钥相同，同一密钥既用于加密又用于解密，所以\n此密钥是不能公开的。\n公钥加密，也叫非对称加密。这种算法加密和解密的密钥不相同，即一个公\n钥，一个私钥，二者成对出现。公钥是公开的密钥，而私钥是只有自己知道。用\n公钥加密的数据只有对应的私钥可以解密，而用私钥加密的数据也只有对应的公\n钥可以解密。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">数字签名有哪些作用？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">数字签名（Digital signature）是只有信息的发送者才能产生的别人无法伪造\n的一段数字串，这段数字串同时也是对信息的发送者发送信息真实性的一个有效\n证明。在利用计算机网络传送报文时，可将公开密钥法用于数字签名，来代替传\n统的签名。\n作用：\n（1）接收者能够核实发送者对报文的签名。\n（2）发送者事后不能抵赖其对报文的签名。\n（3）接收者无法伪造对报文的签名。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">操作系统加固有哪些主要方法？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">（1）操作系统安装与更新\n（2）删除不必要的服务、应用与协议\n（3）对用户和组进行配置\n（4）对资源控制进行配置\n（5）安装额外的安全控制工具\n（6）安全性维护</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是可信计算？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">可信计算是通过保持计算环境及计算逻辑的完整性，为计算平台提供对恶意\n代码、非法操作的自主免疫能力。该技术已经在虚拟化、云计算、工业控制等领\n域应用，并与嵌入式设备、物联网及云端等技术方向加速融合。\n可信计算是指一个可信的组件操作或过程的行为在任意操作条件下是可预\n测的，并能很好地抵抗应用程序软件、病毒以及一定物理干扰所造成的破坏。它\n强调行为的可预测性，并能抵抗各种破坏，达到预期的安全目标。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">简述可信操作系统的主要技术。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">（1）系统可信启动\n引导过程是实现可信计算平台的基点，基于硬件安全模块，例如 TPM/TCM\n或 TPCM 的可信引导，保证从 BIOS、引导程序到操作系统内核，每一个步骤中\n引导实体的完整性，建立一条从平台加电到操作系统安全启动的可信链，即在系\n统的初始化开始就对要获得控制权的代码进行可信验证，这样就能保证启动后的\n操作系统是处于安全可信的状态。\n（2）可信引导\nIntel 可信执行技术（Trusted Execution Technology，TXT）通过硬件内核和子\n系统来控制被访问的计算机资源，如病毒、恶意代码、间谍软件和其他安全威胁\n将不会对计算机软硬件资源构成影响。可信引导（Trusted Boot，Tboot）利用 TXT\n技术和 TPM 对系统内核或者 VMM 执行度量和认证。\n（3）可信内核\n可信内核是指在原来安全内核基础上增加了可信度量模块，如中标麒麟操作\n系统的 CTMM 模块（CS2C Trust Measure Module，CTMM），可扫描和度量系\n统内的所有文件，包括可执行文件、普通文件、动态链接库文件等。\n（4）可信身份认证\n针对传统安全操作系统身份认证机制的问题，基于硬件可信芯片 TPM、TCM\n或 TPCM 的身份认证主要利用可信芯片提供的 Hash 算法功能模块和安全信息存\n储模块，在登录时对系统特权用户进行认证，同时也支持在用户登录时利用可信\n芯片和 IC 卡结合的认证接口对系统用户进行多因子可信身份认证。\n（5）OAT 远程证明\nOAT（Open Attestation）作为远程身份验证的平台，可为网络中的计算机终\n端提供可信的身份验证，OAT 由服务器端和客户端这 2 部分组成，其中服务器\n端 负 责 收 集 客 户 端 的 身 份 验 证 数 据 ， 这 些 数 据 主 要 是 从 客 户 端 的 PCR\n（Producer-Consumer Ratio）中采集。服务器端部署有 CA 证书，每个客户端的\n身份证书都是基于这个 CA 证书颁发的，OAT 不仅可以对主机平台的完整性进行\n验证，还可以对云平台中的虚拟机进行身份验证，保证其可信。\n（6）信任链在云平台中的扩展\n在实现本机信任链的基础上，为进一步保证云平台中虚拟机的安全性，可将\n信任链扩展到虚拟机中。</div>\n  </div>\n</div>\n",
  "chapter11-system-calls": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是系统调用？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">系统调用是操作系统提供给用户的编程接口，是由操作系统提供的、用\n于实现系统各种核心功能的子程序，用户可以通过这些接口使用系统提供的\n各种功能。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">操作系统中一般提供哪些类型的系统调用？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">操作系统中一般提供 6 大类系统调用，分别是：进程控制类、进程通信\n类、文件操作类、存储管理类、设备管理类和信息维护类。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">简述系统调用的执行过程。</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">用户程序通过访管指令或一个由软件引起的内中断处理机构来实现系统\n调用。进行系统调用时，操作系统转入特权模式，从用户态进入核心态，在\n核心态下运行完被调用过程后再返回用户程序。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">API 和系统调用之间有什么关系？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">系统调用是偏底层、偏实现的，而 API 是偏上层、偏接口的。系统调用是\n在操作系统内核里实现的，其修改只要符合操作系统内核的规范并取得内核的管\n理者的同意即可。API 是在用户空间（例如 libc）中实现的，需要遵守行业标准\n或业内标准，是不能随意改变的，一般都有相应的标准委员会来制定和发展 API。\nAPI 的底层实现一般使用的就是系统调用，很多 API 和系统调用是一一对应的。\n但也有特殊情况，比如有的 API 并不使用系统调用，有的系统调用没有对应的\nAPI，有的 API 可能调用了多个系统调用，有的系统调用可能被多个 API 使用。</div>\n  </div>\n</div>\n",
  "chapter11-user-interfaces": "\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">操作系统接口一般有哪几种？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">操作系统接口一般有命令行接口（Command Line Interface，CLI）和图形\n用户接口（Graphics User Interface，GUI）两种交互接口和系统调用（System Call）\n编程接口。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">什么是 Shell？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">Shell 是核心程序之外的指令解释器，既是一个系统程序，同时也是一种\n命令语言和程序设计语言。作为命令语言，它可以交互式地解析、执行用户\n输入的命令；作为程序设计语言，它定义了各种变量和参数，并且提供了许\n多在高级程序设计语言中使用的程序控制结构。Shell 虽然不是操作系统核心\n的一部分，但它调用系统核心中的大部分功能来执行程序、建立文件，并以\n并行的方式来协调各个程序的运行。</div>\n  </div>\n</div>\n\n<div class=\"mb-6 p-6 bg-white border border-slate-200/80 rounded-lg hover:border-indigo-400 hover:shadow-xs transition-all duration-200\">\n  <div class=\"flex items-start gap-3\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-indigo-50 text-indigo-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">Q</span>\n    <div class=\"flex-1 min-w-0\">\n      <h4 class=\"text-base font-bold text-slate-800 leading-snug whitespace-pre-wrap\">常用的 Shell 有哪些？</h4>\n    </div>\n  </div>\n  <div class=\"flex items-start gap-3 mt-4 pt-4 border-t border-slate-100\">\n    <span class=\"inline-flex items-center justify-center w-6 h-6 rounded bg-emerald-50 text-emerald-700 text-xs font-bold flex-shrink-0 mt-0.5 select-none\">A</span>\n    <div class=\"flex-1 min-w-0 text-slate-600 text-sm leading-relaxed whitespace-pre-wrap\">常用的 Shell 包括：（1）ash 是 Linux 操作系统中占用系统资源最少的一\n个小 Shell，它只包含 24 个内部命令，因而使用起来很不方便。（2）bash 是\nLinux 操作系统默认使用的 Shell，内部命令一共有 40 个。（3）ksh 共有 42\n条内部命令，该 Shell 最大的优点是几乎和商业发行版的 ksh 完全兼容，这样\n就可以在不用花钱购买商业版本的情况下尝试商业版本的性能了。（4）csh\n是 Linux 操作系统中比较大的 Shell，共有 52 个内部命令。该 Shell 其实是指\n向/bin/tcsh 这样的一个 Shell，也就是说，csh 其实就是 tcsh。（5）zch 是 Linux\n操作系统中最大的 shell 之一，共有 84 个内部命令。如果只是一般的用途，\n是没有必要安装这样的 Shell 的。</div>\n  </div>\n</div>\n",
};
